### 3. Updated DrillEvaluator

```dart
class DrillEvaluator {
  final ClaudeClient? _claudeClient; // null when offline

  DrillEvaluator({ClaudeClient? claudeClient})
      : _claudeClient = claudeClient;

  Future<DrillEvaluation> evaluate({
    required String expected,
    required String actual,
    required String english,      // for Claude context
    required int difficulty,      // learner level
  }) async {
    // Tier 1: exact match
    final normExpected = KoreanUtils.normalize(expected);
    final normActual = KoreanUtils.normalize(actual);
    if (normExpected == normActual) {
      return DrillEvaluation(score: 1.0, result: DrillResult.pass);
    }

    // Tier 2: jamo edit distance
    final distance = KoreanUtils.jamoEditDistance(expected, actual);
    final maxLen = max(
      KoreanUtils.decomposeString(normExpected).length,
      KoreanUtils.decomposeString(normActual).length,
    );
    final similarity = maxLen == 0 ? 0.0 : 1.0 - (distance / maxLen);

    // Clear pass or fail — no need for Claude
    if (similarity >= 0.8) {
      return DrillEvaluation(score: similarity, result: DrillResult.pass);
    }
    if (similarity < 0.4) {
      return DrillEvaluation(
        score: similarity,
        result: DrillResult.fail,
        feedback: 'Expected: $expected',
      );
    }

    // Tier 3: Ambiguous (0.4-0.8) — ask Claude
    if (_claudeClient != null) {
      try {
        final claudeResult = await _claudeClient!.evaluateResponse(
          expected: expected,
          actual: actual,
          english: english,
          editDistanceScore: similarity,
          difficulty: difficulty,
        );

        final result = claudeResult.correct
            ? (claudeResult.score >= 0.8 ? DrillResult.pass : DrillResult.partial)
            : DrillResult.fail;

        return DrillEvaluation(
          score: claudeResult.score,
          result: result,
          feedback: claudeResult.feedbackEnglish,
          feedbackKorean: claudeResult.feedbackKorean,
        );
      } catch (e) {
        // Claude unavailable — fall back to local score
      }
    }

    // Fallback: use local score directly
    final result = similarity >= 0.6 ? DrillResult.partial : DrillResult.fail;
    return DrillEvaluation(
      score: similarity,
      result: result,
      feedback: 'Expected: $expected',
    );
  }
}
```

