class SyncClient {
  final Dio _dio;

  SyncClient({required String baseUrl, required String apiKey})
      : _dio = Dio(BaseOptions(
          baseUrl: baseUrl,
          headers: {'X-API-Key': apiKey},
        ));

  /// Fetch new/updated lesson items since [since] timestamp.
  Future<SyncResponse> fetchUpdates(DateTime since) async {
    final response = await _dio.get('/api/sync', queryParameters: {
      'since': since.toIso8601String(),
    });
    return SyncResponse.fromJson(response.data);
  }

  /// Upload user progress to the server.
  Future<void> uploadProgress(List<UserProgress> progress) async {
    await _dio.post('/api/progress/batch', data: {
      'progress': progress.map((p) => p.toJson()).toList(),
    });
  }

  /// Check processing status of a session.
  Future<SessionStatus> getSessionStatus(String sessionId) async {
    final response = await _dio.get('/api/sessions/$sessionId/status');
    return SessionStatus.fromJson(response.data);
  }
}
