### 3. Sync repository

#### `lib/data/repositories/sync_repository.dart`

```dart
class SyncRepository {
  final AppDatabase db;
  final SyncClient client;
  final SharedPreferences prefs;

  static const _lastSyncKey = 'last_sync_at';

  SyncRepository({
    required this.db,
    required this.client,
    required this.prefs,
  });

  /// Get the last sync timestamp (or epoch if never synced).
  DateTime get lastSyncAt {
    final stored = prefs.getString(_lastSyncKey);
    if (stored == null) return DateTime.fromMillisecondsSinceEpoch(0);
    return DateTime.parse(stored);
  }

  /// Sync new content from backend to local database.
  Future<SyncResult> syncDown() async {
    try {
      final response = await client.fetchUpdates(lastSyncAt);

      int itemsAdded = 0;

      // Insert new lesson items
      for (final item in response.items) {
        await db.insertLessonItem(_itemToCompanion(item));

        // Initialize progress for new items
        final existing = await db.getProgressForItem(item.id);
        if (existing == null) {
          await db.upsertProgress(UserProgressTableCompanion(
            itemId: Value(item.id),
            nextReviewAt: Value(DateTime.now()),
          ));
        }
        itemsAdded++;
      }

      // Insert dialog scripts and turns
      // (Requires adding dialog tables to Drift — see below)
      for (final dialog in response.dialogs) {
        await _insertDialog(dialog);
      }

      // Update last sync timestamp
      await prefs.setString(_lastSyncKey, response.syncedAt);

      return SyncResult(
        success: true,
        itemsAdded: itemsAdded,
        dialogsAdded: response.dialogs.length,
      );
    } catch (e) {
      return SyncResult(success: false, error: e.toString());
    }
  }

  /// Upload local progress to backend.
  Future<void> syncUp() async {
    final allProgress = await db.getAllProgress();
    final progressModels = allProgress.map((p) => UserProgress(
      itemId: p.itemId,
      easeFactor: p.easeFactor,
      intervalSeconds: p.intervalSeconds,
      nextReviewAt: p.nextReviewAt,
      repetitionCount: p.repetitionCount,
      lastScore: p.lastScore,
      lastReviewedAt: p.lastReviewedAt,
    )).toList();

    await client.uploadProgress(progressModels);
  }

  /// Full sync: download new content, upload progress.
  Future<SyncResult> fullSync() async {
    final downResult = await syncDown();
    if (downResult.success) {
      await syncUp();
    }
    return downResult;
  }
}

class SyncResult {
  final bool success;
  final int itemsAdded;
  final int dialogsAdded;
  final String? error;

  SyncResult({
    required this.success,
    this.itemsAdded = 0,
    this.dialogsAdded = 0,
    this.error,
  });
}
```

