```dart
class NotificationService {
  final FlutterLocalNotificationsPlugin _plugin = FlutterLocalNotificationsPlugin();

  Future<void> init() async {
    const androidSettings = AndroidInitializationSettings('@mipmap/ic_launcher');
    const iosSettings = DarwinInitializationSettings(
      requestAlertPermission: true,
      requestBadgePermission: true,
      requestSoundPermission: true,
    );
    await _plugin.initialize(
      const InitializationSettings(android: androidSettings, iOS: iosSettings),
    );
  }

  /// Schedule a daily reminder at the user's preferred time.
  Future<void> scheduleDailyReminder({
    required TimeOfDay time,
    required int dueItemCount,
  }) async {
    await _plugin.zonedSchedule(
      0, // notification ID
      'Time to practice Korean!',
      dueItemCount > 0
          ? 'You have $dueItemCount items ready for review'
          : 'Keep your streak going with a quick session',
      _nextInstanceOfTime(time),
      const NotificationDetails(
        android: AndroidNotificationDetails(
          'daily_reminder',
          'Daily Practice Reminder',
          channelDescription: 'Reminds you to practice Korean daily',
          importance: Importance.defaultImportance,
          priority: Priority.defaultPriority,
        ),
        iOS: DarwinNotificationDetails(),
      ),
      androidScheduleMode: AndroidScheduleMode.inexactAllowWhileIdle,
      matchDateTimeComponents: DateTimeComponents.time, // repeat daily
      payload: 'daily_reminder',
    );
  }

  /// Cancel daily reminder
  Future<void> cancelDailyReminder() async {
    await _plugin.cancel(0);
  }

  TZDateTime _nextInstanceOfTime(TimeOfDay time) {
    final now = tz.TZDateTime.now(tz.local);
    var scheduled = tz.TZDateTime(tz.local, now.year, now.month, now.day, time.hour, time.minute);
    if (scheduled.isBefore(now)) {
      scheduled = scheduled.add(const Duration(days: 1));
    }
    return scheduled;
  }
}
```

